CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY,email VARCHAR(255) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,full_name VARCHAR(160) NOT NULL,phone VARCHAR(40),role VARCHAR(30) NOT NULL,is_active BOOLEAN NOT NULL DEFAULT TRUE,is_email_verified BOOLEAN NOT NULL DEFAULT FALSE,email_verification_token_hash VARCHAR(128),email_verification_expires_at TIMESTAMP,created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_users_email ON users(email);CREATE INDEX IF NOT EXISTS idx_users_role ON users(role);CREATE INDEX IF NOT EXISTS idx_users_verification_token ON users(email_verification_token_hash);
CREATE TABLE IF NOT EXISTS companies (id SERIAL PRIMARY KEY,name VARCHAR(180) NOT NULL,nip VARCHAR(30),address VARCHAR(255),owner_user_id INTEGER NOT NULL UNIQUE REFERENCES users(id) ON DELETE CASCADE,created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_companies_name ON companies(name);CREATE INDEX IF NOT EXISTS idx_companies_nip ON companies(nip);
CREATE TABLE IF NOT EXISTS doctor_profiles (id SERIAL PRIMARY KEY,user_id INTEGER NOT NULL UNIQUE REFERENCES users(id) ON DELETE CASCADE,company_id INTEGER REFERENCES companies(id) ON DELETE SET NULL,specialization VARCHAR(160),license_number VARCHAR(80),bio TEXT,created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_doctor_profiles_company_id ON doctor_profiles(company_id);
CREATE TABLE IF NOT EXISTS services (id SERIAL PRIMARY KEY,doctor_id INTEGER NOT NULL REFERENCES doctor_profiles(id) ON DELETE CASCADE,name VARCHAR(140) NOT NULL,duration_minutes INTEGER NOT NULL DEFAULT 30,price_cents INTEGER,is_active BOOLEAN NOT NULL DEFAULT TRUE,created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_services_doctor_id ON services(doctor_id);
CREATE TABLE IF NOT EXISTS appointments (id SERIAL PRIMARY KEY,patient_user_id INTEGER REFERENCES users(id) ON DELETE SET NULL,patient_name VARCHAR(160) NOT NULL,patient_email VARCHAR(255) NOT NULL,patient_phone VARCHAR(40),doctor_id INTEGER NOT NULL REFERENCES doctor_profiles(id) ON DELETE CASCADE,company_id INTEGER REFERENCES companies(id) ON DELETE SET NULL,service_id INTEGER REFERENCES services(id) ON DELETE SET NULL,service_name VARCHAR(140) NOT NULL DEFAULT 'Wizyta',starts_at TIMESTAMP NOT NULL,ends_at TIMESTAMP NOT NULL,status VARCHAR(30) NOT NULL DEFAULT 'confirmed',notes TEXT,reminder_sent BOOLEAN NOT NULL DEFAULT FALSE,created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_appointments_patient_user_id ON appointments(patient_user_id);CREATE INDEX IF NOT EXISTS idx_appointments_patient_email ON appointments(patient_email);CREATE INDEX IF NOT EXISTS idx_appointments_doctor_id ON appointments(doctor_id);CREATE INDEX IF NOT EXISTS idx_appointments_company_id ON appointments(company_id);CREATE INDEX IF NOT EXISTS idx_appointments_starts_at ON appointments(starts_at);CREATE INDEX IF NOT EXISTS idx_appointments_status ON appointments(status);
